class Solution {
public:
    string crackSafe(int n, int k) {
        string res(n, '0');
        int vis = 1;
        while (vis < pow(k, n)) {
            for (int i = n - 1; i >= 0; --i) {
                int cur = stoi(res.substr(i));
                res[i] = '0' + ((cur + 1) % k);
                if (stoi(res.substr(i)) == 0 || vis >> stoi(res.substr(i)) & 1 == 0) {
                    vis |= 1 << stoi(res.substr(i));
                    break;
                }
            }
        }
        return res;
    }
};
